#include<bits/stdc++.h>
using namespace std;
int dp1,dp2,n;
string s;
int main() {
	cin>>s;
	n=s.size()-1;
	dp2=s[0]-'a'+1;
	for(int i=1;i<=n;i++){
		if(i%2){
            dp1=max(dp2,dp1+s[i]-'a'+1);
        }else{
            dp2=max(dp1,dp2+s[i]-'a'+1);
        }
	}
    cout<< (n%2?dp1:dp2);
}
